insert into public.document_templates
  (service_slug, document_key, title, category, description, required_by_default, conditional_rule, accepted_file_types, example_description, sort_order, is_active)
select dst.service_slug, dts.document_key, dts.title, dts.category, dts.description, dts.required_by_default, dts.conditional_rule, dts.accepted_file_types, dts.example_description, dts.sort_order, true
from document_service_templates dst
join document_template_sets dts on dts.template = dst.template
on conflict (service_slug, document_key) do update set
  title = excluded.title,
  category = excluded.category,
  description = excluded.description,
  required_by_default = excluded.required_by_default,
  conditional_rule = excluded.conditional_rule,
  accepted_file_types = excluded.accepted_file_types,
  example_description = excluded.example_description,
  sort_order = excluded.sort_order,
  is_active = excluded.is_active,
  updated_at = now();
